const html = `
<!DOCTYPE html>
<html lang="es">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Booking Titanium | Sistema de Reservas</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@300;500;800&family=Manrope:wght@400;600&display=swap" rel="stylesheet">
    <style>
        :root {
            --bg-base: #050505;
            --titanium-light: #e0e5ec;
            --titanium-dark: #8c97a7;
            --accent-cyan: #00f0ff;
            --accent-purple: #7000ff;
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            background-color: var(--bg-base);
            color: var(--titanium-light);
            font-family: 'Manrope', sans-serif;
            min-height: 100vh;
            display: flex;
            flex-direction: column;
            overflow-x: hidden;
            position: relative;
        }

        /* Mesh Gradient Background */
        .ambient-bg {
            position: fixed;
            top: 0;
            left: 0;
            width: 100vw;
            height: 100vh;
            z-index: -1;
            background: 
                radial-gradient(circle at 15% 50%, rgba(0, 240, 255, 0.08), transparent 50%),
                radial-gradient(circle at 85% 30%, rgba(112, 0, 255, 0.12), transparent 50%);
            filter: blur(60px);
            animation: pulse 15s ease-in-out infinite alternate;
        }

        /* Noise overlay */
        .noise-overlay {
            position: fixed;
            top: 0; left: 0; width: 100vw; height: 100vh;
            z-index: -1;
            opacity: 0.03;
            background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E");
            pointer-events: none;
        }

        @keyframes pulse {
            0% { transform: scale(1); opacity: 0.8; }
            100% { transform: scale(1.1); opacity: 1; }
        }

        nav {
            padding: 2rem 4rem;
            display: flex;
            justify-content: space-between;
            align-items: center;
            border-bottom: 1px solid rgba(255,255,255,0.05);
        }

        .logo {
            font-family: 'Outfit', sans-serif;
            font-weight: 800;
            font-size: 1.5rem;
            letter-spacing: 2px;
            text-transform: uppercase;
            background: linear-gradient(90deg, var(--titanium-light), var(--titanium-dark));
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
        }

        main {
            flex: 1;
            display: flex;
            align-items: center;
            justify-content: center;
            padding: 4rem;
        }

        .hero-content {
            max-width: 800px;
            text-align: center;
            z-index: 1;
        }

        .badge {
            display: inline-block;
            padding: 0.5rem 1.5rem;
            border-radius: 100px;
            font-size: 0.8rem;
            font-weight: 600;
            letter-spacing: 1px;
            text-transform: uppercase;
            background: rgba(255,255,255,0.03);
            border: 1px solid rgba(255,255,255,0.1);
            margin-bottom: 2rem;
            backdrop-filter: blur(10px);
        }

        h1 {
            font-family: 'Outfit', sans-serif;
            font-weight: 300;
            font-size: 4.5rem;
            line-height: 1.1;
            margin-bottom: 1.5rem;
            letter-spacing: -1px;
        }

        h1 span {
            font-weight: 800;
            background: linear-gradient(45deg, var(--accent-cyan), var(--accent-purple));
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            position: relative;
        }

        p.subtitle {
            font-size: 1.2rem;
            color: var(--titanium-dark);
            margin-bottom: 3rem;
            max-width: 600px;
            margin-inline: auto;
            line-height: 1.6;
        }

        .cta-container {
            display: flex;
            gap: 1.5rem;
            justify-content: center;
        }

        .btn {
            padding: 1rem 2.5rem;
            font-family: 'Outfit', sans-serif;
            font-weight: 600;
            font-size: 1rem;
            border-radius: 4px;
            cursor: pointer;
            transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
            text-decoration: none;
            letter-spacing: 0.5px;
        }

        .btn-primary {
            background: var(--titanium-light);
            color: var(--bg-base);
            border: none;
            position: relative;
            overflow: hidden;
        }

        .btn-primary:hover {
            background: #fff;
            box-shadow: 0 0 30px rgba(255,255,255,0.2);
            transform: translateY(-2px);
        }

        .btn-secondary {
            background: transparent;
            color: var(--titanium-light);
            border: 1px solid rgba(255,255,255,0.2);
            backdrop-filter: blur(10px);
        }

        .btn-secondary:hover {
            border-color: var(--titanium-light);
            background: rgba(255,255,255,0.05);
        }

        /* Custom cursor interaction */
        .cursor-glow {
            width: 400px;
            height: 400px;
            background: radial-gradient(circle, rgba(255,255,255,0.03) 0%, transparent 70%);
            border-radius: 50%;
            position: fixed;
            pointer-events: none;
            z-index: 9999;
            transform: translate(-50%, -50%);
            transition: background 0.3s ease;
        }

        @media (max-width: 768px) {
            h1 { font-size: 3rem; }
            nav { padding: 1.5rem 2rem; }
            main { padding: 2rem; }
            .cta-container { flex-direction: column; }
        }
    </style>
</head>
<body>
    <div class="ambient-bg"></div>
    <div class="noise-overlay"></div>
    <div class="cursor-glow" id="cursorGlow"></div>

    <nav>
        <div class="logo">Titanium</div>
        <a href="#" class="btn btn-secondary" style="padding: 0.5rem 1.5rem; font-size: 0.9rem;">Acceso Staff</a>
    </nav>

    <main>
        <div class="hero-content">
            <div class="badge">IA + Automatización</div>
            <h1>Gestión de Reservas <br><span>Inteligente.</span></h1>
            <p class="subtitle">Reserva, consulta y administra tus turnos en segundos. Potenciado por Inteligencia Artificial y un ecosistema omnicanal fluido.</p>

            <div class="cta-container">
                <!-- Reemplazar el enlace con el del bot de Telegram de producción -->
                <a href="https://t.me/TuBotDeTitanium" target="_blank" class="btn btn-primary">Reservar vía Telegram</a>
                <a href="#" class="btn btn-secondary">Saber más</a>
            </div>
        </div>
    </main>

    <script>
        // Interactive subtle glow following the cursor
        const glow = document.getElementById('cursorGlow');

        document.addEventListener('mousemove', (e) => {
            glow.style.left = e.clientX + 'px';
            glow.style.top = e.clientY + 'px';
        });

        // Reveal animation on load
        document.addEventListener("DOMContentLoaded", () => {
            const elements = document.querySelectorAll('.badge, h1, .subtitle, .cta-container');
            elements.forEach((el, index) => {
                el.style.opacity = '0';
                el.style.transform = 'translateY(20px)';
                el.style.transition = 'all 0.8s cubic-bezier(0.16, 1, 0.3, 1)';
                setTimeout(() => {
                    el.style.opacity = '1';
                    el.style.transform = 'translateY(0)';
                }, 100 + (index * 150));
            });
        });
    </script>
</body>
</html>
`;

return [
  {
    json: {
      html: html
    }
  }
];

